mapper.select:



		AND menu_name like concat('%', #{menuName}, '%')


		AND visible = #{visible}


		AND status = #{status}


order by parent_id, order_num

		select distinct m.menu_id, m.parent_id, m.menu_name, m.path, m.component, m.`query`, m.visible, m.status, ifnull(m.perms,'') as perms, m.is_frame, m.is_cache, m.menu_type, m.icon, m.order_num, ifnull(m.is_platform,'0') as is_platform, m.create_time
		from sys_menu m
		where exists (
			select 1 from sys_user_menu um
			where um.menu_id = m.menu_id
			and um.user_id = #{params.userId}
		)

            AND m.menu_name like concat('%', #{menuName}, '%')


            AND m.visible = #{visible}


            AND m.status = #{status}

		order by m.parent_id, m.order_num

select m.menu_id from sys_menu m left join sys_role_menu rm on m.menu_id = rm.menu_id where rm.role_id = #{roleId}
and m.menu_id not in (select m.parent_id from sys_menu m inner join sys_role_menu rm on m.menu_id = rm.menu_id and rm.role_id = #{roleId})
order by m.parent_id, m.order_num

mapper.update:
update sys_menu
menu_name = #{menuName}, parent_id = #{parentId}, order_num = #{orderNum}, path = #{path}, component = #{component}, `query` = #{query}, is_frame = #{isFrame}, is_cache = #{isCache}, menu_type = #{menuType}, visible = #{visible}, status = #{status}, perms = #{perms}, icon = #{icon}, is_platform = #{isPlatform}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where menu_id = #{menuId}
